{
	"name": "Static Image + Content",
	"schema": [
        {
            "type": "tab",
            "label": "Static Content",
            "sections": [
                { 
                    "label": "Static Content",
                    "settings": [
                        {
                            "type": "input",
                            "id": "heading_text",
                            "label": "Heading Text",
                            "default": "Type a Heading"
                        },
                        {
                            "type": "imageManager",
                            "id": "image",
                            "label": "Image",
                            "default": {
                                "src": "https://placehold.it/250x250",
                                "type": "IMAGE_MANAGER"
                            }
                        },
                        {
                            "type": "range",
                            "label": "Image Width",
                            "id": "width",
                            "default": "250",
                            "typeMeta": {
                                "rangeValues": {
                                    "min": 100,
                                    "max": 1200,
                                    "step": 1,
                                    "unit": "px"
                                }
                            }
                        },
                        {
                            "type": "text",
                            "label": "Text Block Content",
                            "id": "text_block",
                            "default": "Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed pellentesque tortor ante, id maximus massa volutpat et. Aliquam at leo a purus condimentum tristique. Nulla feugiat enim quis neque suscipit, sed dictum quam tempor. Morbi purus metus, porta tincidunt justo eget, mollis volutpat justo. Suspendisse enim est, tristique vel nisl in, facilisis aliquam risus. Nunc placerat quam quam, eget blandit augue finibus sed. Donec in facilisis urna, eu egestas diam. Maecenas consequat a lacus et pharetra. Nullam sodales mi sed libero venenatis placerat. Proin quis pharetra metus. Suspendisse elementum at libero nec dignissim. In convallis imperdiet turpis eget hendrerit. Quisque sapien enim, vestibulum vitae ullamcorper et, rutrum faucibus nunc."
                        }
                    ]
                }
            ]
        }
    ],
    "template": "<h2>{{heading_text}}</h2>\n<img src=\"{{image.src}}\" width=\"{{width}}\" />\n<div>{{text_block}}</div>"
}

{
	"name": "Array of Products Widget Demo",
	"schema": [
        {
            "type": "array",
            "label": "Products",
            "id": "products",
            "defaultCount": 3,
            "entryLabel": "Product",
            "schema": [
                {
                    "type": "tab",
                    "label": "Product Settings",
                    "sections": [
                        {
                            "label": "Configure the Product",
                            "settings": [
                                {
                                    "type": "productId",
                                    "label": "Select a Product",
                                    "id": "productId"
                                },
                                {
                                    "type": "productImage",
                                    "label": "Image",
                                    "id": "image",
                                    "typeMeta": {
                                        "reference": "productId"
                                    }
                                }
                            ]
                        }
                    ]
                }
            ]
        }
    ],
    "template": "<div style=\"display: flex; flex-wrap: wrap\">\n    {{#each products}}\n        <div style=\"flex-grow: 1; width: 33%\">\n            <img src=\"{{image.src}}\" width=\"200px\"/>\n            <div>Product ID: {{productId}}</div> \n        </div>\n    {{/each}}\n</div>"
}

