{
    "name": "Variant List",
    "storefront_api_query": "query productById(  $productId: Int) {  site {    product(entityId: $productId) {      entityId      name      plainTextDescription(characterLimit: 1000)      defaultImage {        ...ImageFields      }      variants {        edges {          node {            ... VariantFields            defaultImage {              ... ImageFields            }          }        }      }    }  }}fragment VariantFields on Variant {  entityId  sku  defaultImage {    ... ImageFields  }  prices {    price{      ... MoneyFields    }    salePrice {      ... MoneyFields    }  }}fragment ImageFields on Image {  url160wide: url(width: 160)  url320wide: url(width: 320)  url640wide: url(width: 640)  url960wide: url(width: 960)  url1280wide: url(width: 1280)}fragment MoneyFields on Money {  value  currencyCode}",
    "schema": [
        {
            "type": "hidden",
            "settings": [
                {
                    "type": "graphQl",
                    "id": "graphQueries",
                    "typeMeta": {
                        "mappings": {
                            "productId": {
                                "reads": "productId",
                                "type": "Int"
                            }
                        }
                    }
                }
            ]
        },
        {
            "type": "tab",
            "label": "Product Configuration",
            "sections": [
                {
                    "label": "Product",
                    "settings": [
                        {
                            "type": "productId",
                            "label": "Select a Product",
                            "id": "productId"
                        }
                    ]
                }
            ]
        }
    ],
    "template": "<div style=\"width:100%\">\n    <img \n     src=\"{{_.data.site.product.defaultImage.url960wide}}\"\n     srcset=\"{{_.data.site.product.defaultImage.url320wide}} 320w\n     {{_.data.site.product.defaultImage.url640wide}} 640w\n     {{_.data.site.product.defaultImage.url960wide}} 960w\n     {{_.data.site.product.defaultImage.url960wide}} 1280w\"\n     style=\"display: block;max-width: 33%; margin-left:auto; margin-right:auto\" />\n    </div>\n    <div style=\"display: block;margin-left:auto; margin-right:auto;\">\n        <strong style=\"display: block;\">{{_.data.site.product.name}}</strong>\n        <em style=\"display: block;\">{{_.data.site.product.plainTextDescription}}</em>\n        <ul style=\"list-style: none;\">\n        {{#each _.data.site.product.variants.edges }}\n            <li>\n                <div style=\"display:flex;flex-direction: row\">\n                    <div style=\"width:160px;flex-grow: 1\">\n                        {{#if node.defaultImage}}\n                        <img src=\"{{node.defaultImage.url160wide}}\"/>\n                        {{/if}}\n                    </div>\n                    <div style=\"flex-grow: 1\">\n                        <span>\n                            {{toFixed node.prices.price.value 2}} {{node.prices.price.currencyCode}} \n                        </span>\n                    </div>\n                    <div style=\"flex-grow: 3\">\n                        <strong>{{node.sku}}</strong>\n                    </div>\n                </div>\n            </li>\n        {{/each}}\n        </ul>\n    </div>\n</div>"
}

